export function qnaForModule(moduleId) {
  return QNA_BANK[moduleId] || null;
}

export function qnaQuestionCount(entry) {
  if (!entry) return 0;
  const inBeats = (entry.beats || []).reduce((n, b) => n + b.questions.length, 0);
  return inBeats + (entry.cases || []).length;
}
